var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"같은 시각. 챔버, <color=#ffd34c>구 콜롬비아 폐광</color> 인근 무인지대.","JPN":"同時刻、チェンバー。<color=#ffd34c>旧コロンビア廃鉱</color>付近の無人地帯。","ENG":"Meanwhile. Chamber, <color=#ffd34c>Abandoned Mine in Old Colombia</color> near No-man's land.","TWN":"同一時間，密室，<color=#ffd34c>舊哥倫比亞廢礦</color>附近無人地帶"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"대균열의 확장이 시작됐군요.","JPN":"大亀裂の拡張が始まりましたね。","ENG":"The expansion of the Grand Dimension Crevice has begun.","TWN":"大峽谷開始擴張了。"},"stage":{"bg":"WAREHOUSE_01","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L6_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"심층에 위치한 챔버 대균열의 영향력이 이정도라면, 다른 지부는 말할 것도 없을 겁니다.","JPN":"深層にあるチェンバー大亀裂の影響がこれほどなら、他の支部は言うまでもないでしょう。","ENG":"If the depths of Chamber's Grand Dimension Crevice already has this much influence, the other branches will be even worse.","TWN":"如果位於深層的密室大峽谷具有這樣的影響力，那其他分部就不用說了。"},"stage":{"bg":"WAREHOUSE_01","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"그래. 마침 관리국 최고 등급 재난 경보도 발령된 참이네.","JPN":"そうね。ちょうど管理局の最高ランクの災難警報も発令されたわ。","ENG":"Yeah. The Administration just issued its highest-level disaster alert, too.","TWN":"沒錯，正好管理局也發布最高等級災難警報了。"},"stage":{"bg":"WAREHOUSE_01","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L10_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"타기리온이라는 녀석. 우리가 예상한 것보다 훨씬 본격적이야.","JPN":"タギリオンってやつ、アタシたちが予想してたよりずっと本格的ね。","ENG":"This Thagirion is a lot more serious than we expected.","TWN":"那個叫塔基里翁的傢伙，比我們想像中還要認真。"},"stage":{"bg":"WAREHOUSE_01","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"하하. 겁이라도 먹었어, 실비아?","JPN":"はは。怖気づいたのか、シルビア？","ENG":"Haha. Getting scared, Sylvia?","TWN":"哈哈，妳怕了嗎，希爾維亞？"},"stage":{"bg":"WAREHOUSE_01","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL"},{"id":"L15_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"뭐래. 이런 상황에서 태연하게 구는 건 너밖에 없거든?","JPN":"何よ、こんな状況で平然としていられる人ってあんたぐらいしかいないからね。","ENG":"Please. You're the only one who can act carefree right now.","TWN":"在說什麼？這種情況下只有我能表現出一副泰然自若的樣子。"},"stage":{"bg":"WAREHOUSE_01","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L17_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"좋은 게 좋은 거지. 어차피 맞닥트린 상황이라면 긍정적으로 생각하자고.","JPN":"まあまあ、立ち向かうしかないならポジティブに考えようじゃないか。","ENG":"Gotta keep it positive. If the situation's here, face it head on.","TWN":"不管怎樣都是好事，反正既然碰上了就要正向思考。"},"stage":{"bg":"WAREHOUSE_01","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"복잡해 보이지만, 정면승부를 거는 적에게 이쪽도 전력으로 부딪친다.","JPN":"複雑そうに見えるが、真正面からかかってくる敵にはこっちも全力で勝負する。","ENG":"It looks complicated, but if they come straight at us, we hit back with full force.","TWN":"雖然看起來很複雜，但面對正面交戰的敵人，我們也要全力以赴。"},"stage":{"bg":"WAREHOUSE_01","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"어때, 심플하지?","JPN":"どうだ、シンプルだろ？","ENG":"Simple, right?","TWN":"如何，很簡單吧？"},"stage":{"bg":"WAREHOUSE_01","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"근육 바보인 너야 그렇지. 우린 이것저것 하느라 바쁠 예정이라고.","JPN":"筋肉バカはそれでいいかもしれないけど、アタシたちは色々やるから忙しくなる予定なの。","ENG":"Says the musclehead. The rest of us will be busy juggling a thousand things.","TWN":"因為妳做事只憑一股熱血，我們會忙著做各種事情。"},"stage":{"bg":"WAREHOUSE_01","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L23_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"두 분. 거기까지 하시죠.","JPN":"2人とも、そこまでにしましょう。","ENG":"You two, that's enough.","TWN":"兩位，就到此為止吧。"},"stage":{"bg":"WAREHOUSE_01","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L25_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"작전에 앞서, 팀의 원활한 소통을 위한 통신 점검을 진행하겠습니다.","JPN":"作戦に先立ち、チームの円滑なコミュニケーションのために通信の点検を始めます。","ENG":"Before the operation, we'll run a comms check for any problems.","TWN":"在作戰之前，為了讓團隊溝通順暢，我要進行通訊檢查。"},"stage":{"bg":"WAREHOUSE_01","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L26_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"사전에 공유한대로 이번 작전의 지휘는 제가 맡게 되었으나.","JPN":"事前に共有したとおり、今回の作戦は僕が指揮を執ることになりましたが。","ENG":"As previously shared, I'll be commanding this operation.","TWN":"按照事前共享的內容，這次作戰由我負責指揮。"},"stage":{"bg":"WAREHOUSE_01","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"특정 상황에서의 변수 발생 시, 각 조에 소속된 명령권자의 지시를 우선적으로 따라주시길.","JPN":"特定の状況で予想外のことが発生した場合、各組に所属している命令権者の指示を優先してください。","ENG":"However, if variables arise, follow the order of the commander assigned to your unit.","TWN":"發生特定情況變數時，請優先遵照各組下達命令之人的指示。"},"stage":{"bg":"WAREHOUSE_01","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L28_1","type":"subtitle","speaker":null,"text":{"KOREA":"챔버 대균열 작전팀, 알파\\n지휘관, 카일 웡 소령.","JPN":"チェンバー大亀裂作戦チーム、アルファ\\n指揮官、カイル・ウォン少佐","ENG":"Chamber's Grand Dimension Crevice Ops Team, Alpha\\nCommander, Major Kyle Wong.","TWN":"密室大峽谷作戰組，阿爾法\\n指揮官，凱爾少校。"},"stage":{"bg":"WAREHOUSE_01","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"각 팀. 응답 바랍니다.","JPN":"各チーム、応答願います。","ENG":"All teams, respond.","TWN":"各組請回答。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L33_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"여기는 HQ. 선로전환기 프로토타입의 제작은 끝마쳤다.","JPN":"こちらはHQ。線路転換器プロトタイプの製作は完了した。","ENG":"This is HQ. The prototype Track Switcher is complete.","TWN":"這裡是HQ，線路轉換器原型製作完成。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"북방합의체로부터 제공받은 이터니움 기술로 어떻게든 계면 붕괴는 막고 있지만…….","JPN":"北方合意体から提供してもらったエタニウム技術でなんとか界面崩壊は防いでいるが……","ENG":"Using Eternium tech supplied by the Northern Union, we're barely preventing the surface meltdown...","TWN":"雖然正在想盡辦法用北方和議會提供的永恆之金技術阻止介面塌陷……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"효율성이 최악인지라 이터니움 소모 속도가 상당해. 이건 임시방편에 불과할 거다.","JPN":"効率が最悪で、エタニウムの消耗がかなり速い。これじゃ一時凌ぎにしかならないと思うぞ。","ENG":"...But efficiency is awful, so Eternium consumption is huge. This should only be a stopgap.","TWN":"但可能是效率極差，永恆之金消耗速度非常快，這應該只是權宜之計。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"최적인 상태로 운용하려면, 역시 대균열 심부에 직접 설치해야겠지.","JPN":"最適の状態で運用するためには、やっぱり大亀裂深部に直接設置すべきだな。","ENG":"To run it optimally, we'll have to install it directly in the Grand Dimension Crevice's depths.","TWN":"如果想以最佳狀態運用，果然還是要直接設置在大峽谷深處。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"subtitle","speaker":null,"text":{"KOREA":"챔버 대균열 작전팀, HQ.\\n리더, 존 메이슨","JPN":"チェンバー大亀裂作戦チーム、HQ。\\nリーダー、ジョン・メイソン","ENG":"Chamber's Grand Dimension Crevice Ops Team, HQ.\\nLeader, John Mason.","TWN":"密室大峽谷作戰組，HQ。\\n隊長，約翰·梅森"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"당장은 시민들이 대피할 시간을 벌 수 있다면 충분합니다.","JPN":"今は市民が避難できる時間を稼ぐだけで十分です。","ENG":"For now, if we can buy civilians time to evacuate, that's enough.","TWN":"只要能暫時爭取居民撤離的時間就夠了。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"대균열을 막아내는 건 부차적인 문제로 생각하시죠.","JPN":"大亀裂を止めるのはその次に考えましょう。","ENG":"Treat sealing the Grand Dimension Crevice as a secondary objective.","TWN":"就把阻擋大峽谷當成次要問題吧。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"LOOK_REPLACER_NULL_NULL","text":{"KOREA":"마찬가지로, HQ. 대균열 내부에서의 통신망은 확보되었다.","JPN":"同じく、HQ。大亀裂内部の通信網は確保した。","ENG":"Likewise, HQ. Comms are secured within the Grand Dimension Crevice interior.","TWN":"這邊也一樣，HQ。已確保大峽谷內部的通訊網。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOOK_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"LOOK_REPLACER_NULL_NULL","text":{"KOREA":"시뮬레이션 결과. 대균열 심층으로 진입하더라도 양방향 소통은 원활할 예정이다.","JPN":"シミュレーション結果。大亀裂深部に進入しても両方向通信は円滑に行える。","ENG":"Simulations say two-way comms should remain stable even after we enter its depths.","TWN":"模擬結果，就算進入大峽谷深處，雙向溝通也會暢通無阻。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOOK_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"MAVERICK_NPC_NULL_NULL","text":{"KOREA":"앨버트… 우리… 아직 살아있냐……?","JPN":"アルバート……まだ、生きてるよな……？","ENG":"Albert... Are we... still alive...?","TWN":"亞伯特…我們…還活著嗎……？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOOK_REPLACER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"ALBERT_NPC_NULL_NULL","text":{"KOREA":"악마 같은 놈들… 하이테크 통신기를 가상좌표 기준으로 죄다 뜯어 고치라니…….","JPN":"悪魔みたいなやつらめ……ハイテク通信機を仮想座標基準に全部直せだなんて……","ENG":"Devilish bastards... Making us rebuild high-tech comms around virtual coordinates...","TWN":"這些惡魔般的傢伙…居然以虛擬座標為標準大改所有高科技通訊設備……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOOK_REPLACER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"ALBERT_NPC_NULL_NULL","text":{"KOREA":"심층 환경이라 어쩔 수 없다지만… 각 세션마다 유효한 문자열을 일일이 부여했다고…….","JPN":"深層環境だから仕方ないとはいえ……各セッションに有効な文字列をいちいち与えたのよ……","ENG":"I get that it's because of the Deep Floor conditions, but assigning valid strings to every single session...","TWN":"因為是深層環境也無可奈何…但每個區段都賦予了有效的字串……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOOK_REPLACER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"LOOK_REPLACER_NULL_NULL","text":{"KOREA":"약간의 희생이 있었지만, 다-크 세븐의 힘으로 불가능을 가능으로 만들었지.","JPN":"少々の犠牲はあったが、ダーークセブンの力で不可能を可能にした。","ENG":"With some sacrifice, Daark Seven made the impossible possible.","TWN":"雖然做出一些犧牲，但憑藉Dark 7的力量，把不可能變成可能了。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOOK_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"여기는 브라보. 시민들의 대피도 차질 없이 진행되고 있네.","JPN":"こちらはブラボー。市民の避難も滞りなく進んでいる。","ENG":"This is Bravo. Civilian evacuations are proceeding smoothly.","TWN":"這裡是布拉伯，市民撤離也正在順利進行。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"합중국 주요 인사들을 안전한 곳에 모시는 대로 나도 현장으로 합류하지.","JPN":"合衆国の要人たちを安全な場所へ送ってから、私も現場に合流する。","ENG":"Once key States personnel have evacuated to some place safe, I'll join you on site.","TWN":"把合眾國主要人士送到安全的地方後，我也會到現場會合。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"subtitle","speaker":null,"text":{"KOREA":"챔버 대균열 작전팀, 브라보\\n리더, 마리아 안토노프 중장","JPN":"チェンバー大亀裂作戦チーム、ブラボー\\nリーダー、マリア・アントノフ中将","ENG":"Chamber's Grand Dimension Crevice Ops Team, Bravo\\nLeader, Lt. Gen. Maria Antonov.","TWN":"密室大峽谷作戰組，布拉伯\\n隊長，瑪麗亞·安東諾夫中將"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"대균열 쪽은 맡기겠네, 카일.","JPN":"大亀裂のほうは任せた、カイル。","ENG":"I'm leaving the Grand Dimension Crevice to you, Kyle.","TWN":"大峽谷那邊就交給你了，凱爾。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"예. 반드시 작전을 성공시키겠습니다.","JPN":"はい。必ず作戦を成功させます。","ENG":"Yes, ma'am. We'll see this through.","TWN":"是，我一定會讓作戰成功。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L11_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"저… 힘내세요.","JPN":"あの……頑張りましょう。","ENG":"Um... Good luck out there.","TWN":"那個…請加油。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L12_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"그래도 여긴 현장에 비하면 나은 편이니까요.","JPN":"ここは現場に比べたらマシなほうですから。","ENG":"It's still better here than on site, relatively speaking.","TWN":"這裡比起現場還是好多了。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"아마도…….","JPN":"たぶん……","ENG":"Probably...","TWN":"應該……"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"민서 양. 저희 인생은 왜 항상 이 모양이죠?","JPN":"ヒミコさん、秋たちの人生はなんでいつもこうなんでしょう？","ENG":"Minseo, why is our life always like this?","TWN":"旼序小姐，我們的人生為什麼總是這樣？"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"모처럼 알바비를 모아 챔버 관광이라는 호의호식을 누리려 했는데, 동원령이 말이냐고요.","JPN":"バイトの給料を貯めて、チェンバー観光という豪華な休みを満喫するはずだったのに、動員命令だなんて。","ENG":"We saved up for a cushy Chamber sightseeing trip only to be hit with a mobilization order.","TWN":"好不容易把打工費存起來，打算享受密室觀光，結果卻發布動員令，這像話嗎？"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"저희 같은 약골들로 뭘 하려는 걸까요…….","JPN":"ヒミコたちのような雑魚キャラに何をやらせるつもりなんでしょうか……","ENG":"What could they possibly want with weaklings like us...?","TWN":"像我們這樣弱不禁風的人要做什麼……"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L20_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"총알받이… 총알받이가 분명해요. 기회가 되면 분명 저흴 버릴 거예요…….","JPN":"弾除け……弾除けに違いありません。いざとなったらきっと捨てられます……","ENG":"Cannon fodder... We're definitely cannon fodder. They'll ditch us at the first chance...","TWN":"炮灰…肯定是當炮灰…要是有機會一定會拋棄我們……"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"XIEN_FREEDOM_NULL_NULL","text":{"KOREA":"친구들. 무릇 사나이라면 국가의 부름에 마땅히 응해야지.","JPN":"2人とも、漢なら国の呼びかけに応えるべきだ。","ENG":"Friends, a true man answers his nation's call.","TWN":"朋友們，如果是條好漢就應該響應國家的號召。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIEN_FREEDOM_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"XIEN_FREEDOM_NULL_NULL","text":{"KOREA":"작은 일에 최선을 다하면 남을 감동시키고, 그리하면 성숙해져 천하가 변하는 법이라네.","JPN":"些細なことでも全力を尽くせば人に感動を与え、そうやって成長していくと世界が変わるものだぞ。","ENG":"Do your best in small things and you'll move others. The world changes as you grow.","TWN":"小事全力以赴就能感動他人，這樣一來就會變得成熟，天下也會有所改變。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIEN_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"멀쩡한 사람이 없어요, 민서. 저흰 이제 폐기를 앞둔 삼각김밥이나 다름없다고요…….","JPN":"まともな人がいません。ヒミコさん、秋たちはもう廃棄寸前のおにぎりです……","ENG":"Nobody here is normal, Minseo. We're like convenience-store fast food on the verge of expiring...","TWN":"沒有半個正常人，旼序，我們現在跟快被丟棄的三角飯糰沒兩樣……"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L27_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"이딴 현실 망겜. 그냥 섭종하라지…….","JPN":"こんなリアルクソゲー、サ終すればいい……","ENG":"This trash reality game. Just shut down the servers already...","TWN":"這種現實慘敗的遊戲，乾脆關閉伺服器吧……"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"XIEN_FREEDOM_NULL_NULL","text":{"KOREA":"훗훗훗. 가까이 있는 전쟁터조차 먼 곳에서는 우리의 활약이 활짝 필 도원향이니.","JPN":"フッフッフ。近くの戦場も遠くから見れば我々の活躍が花開く桃源郷なのだ。","ENG":"Hehehe. Even a nearby battlefield is a peach blossom spring where our deeds will bloom afar!","TWN":"呵呵呵，就連近處的戰場，在遠處將會是我們表現十分活躍的桃花源。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_DESPAIR"},"C":{"char_id":"XIEN_FREEDOM_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L29_1","type":"dialog","speaker":"XIEN_FREEDOM_NULL_NULL","text":{"KOREA":"숨겨서 무엇하랴! 이번에야말로 영웅호걸의 시간이다!!","JPN":"時が来た！　今度こそ英雄の時間だ！","ENG":"Why hide it?! This, at last, is the hour of heroes!","TWN":"躲躲藏藏幹什麼！這次是英雄豪傑的時間！！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_DESPAIR"},"C":{"char_id":"XIEN_FREEDOM_NULL_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_TADA"},{"id":"L30_1","type":"subtitle","speaker":null,"text":{"KOREA":"챔버 대균열 작전팀, 브라보\\n<color=#ffd34c>프리</color>덤 라이더즈","JPN":"チェンバー大亀裂作戦チーム、ブラボー\\n<color=#ffd34c>フリー</color>ダム・ライダーズ","ENG":"Chamber's Grand Dimension Crevice Ops Team, Bravo\\n<color=#ffd34c>Free</color>dom Riders","TWN":"密室大峽谷作戰組，布拉伯\\n<color=#ffd34c>自由</color>騎士"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_DESPAIR"},"C":{"char_id":"XIEN_FREEDOM_NULL_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L34_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"어디 아파요, 민서?","JPN":"ヒミコさん、具合悪いんですか？","ENG":"You okay, Minseo?","TWN":"妳哪裡不舒服嗎，旼序？"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"아뇨, 갑자기 제4의 벽 너머의 누군가가 저흴 억까하는 기분이 들어서요.","JPN":"いいえ。ふと第4の壁の向こうの誰かが、ヒミコたちをディスってるような気がして。","ENG":"I dunno, feels like someone beyond the fourth wall is slandering us for no reason.","TWN":"沒有，感覺第四面牆另一端有人在辱罵我們。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"혹시, 나도 해야 하는 걸까?","JPN":"もしかして、私もしなければならないのか？","ENG":"Do I need to contribute too?","TWN":"難道我也應該加入嗎？"},"stage":{"bg":"YOO_MI_NA_SPECIAL","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L39_1","type":"subtitle","speaker":null,"text":{"KOREA":"그라운드 제로 작전팀\\n지휘관, 펠릭스","JPN":"グラウンド・ゼロ作戦チーム\\n指揮官、フェリックス","ENG":"Ground Zero Ops Team\\nCommander, Felix","TWN":"Ground Zero作戰組\\n指揮官，緋莉克絲"},"stage":{"bg":"YOO_MI_NA_SPECIAL","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"물론입니다. 작전상 북방합의체 역시 합중국 산하 부대로 편제되었으니까요.","JPN":"もちろんです。作戦上、北方合意体も合衆国傘下の部隊として編成されていますからね。","ENG":"Of course. For this operation, the Northern Union is organized under the States' chain of command.","TWN":"當然，北方和議會在作戰上還是被編制為合眾國所屬部隊。"},"stage":{"bg":"YOO_MI_NA_SPECIAL","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L42_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"다른 의도가 없다면, 이쪽 지시를 따르는 것은 물론 즉각적인 상황 공유를 부탁드립니다.","JPN":"他の意図がないなら、こちらの指示に従うのはもちろん、随時状況を共有してください。","ENG":"Unless you have other intentions, follow our directives and share updates immediately.","TWN":"如果沒有其他意圖，就請妳聽從這邊的指示，並且立即分享情況。"},"stage":{"bg":"YOO_MI_NA_SPECIAL","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"걱정 마. 그라운드 제로는 북방합의체만으로 충분해.","JPN":"心配するな。グラウンド・ゼロは北方合意体だけで十分だ。","ENG":"Don't worry. Ground Zero is well within the Northern Union's capability.","TWN":"別擔心，Ground Zero只要有北方和議會就夠了。"},"stage":{"bg":"YOO_MI_NA_SPECIAL","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"아니면 챔버 대균열을 막는데 도움이 필요한 거려나?","JPN":"それとも、チェンバー大亀裂を止めるために助けが必要なのか？","ENG":"Unless you need help stopping Chamber's Grand Dimension Crevice?","TWN":"還是阻擋密室大峽谷需要幫忙嗎？"},"stage":{"bg":"YOO_MI_NA_SPECIAL","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"일시 협력관계라고는 하나, 합중국이 북방합의체의 과오를 용인한단 것은 아닙니다.","JPN":"一時的な協力関係とはいえ、合衆国が北方合意体の過ちを許したわけではありません。","ENG":"Temporary cooperation doesn't mean the States condone the Northern Union's past misdeeds.","TWN":"雖然是暫時合作關係，但並不代表合眾國容忍了北方和議會的錯誤。"},"stage":{"bg":"YOO_MI_NA_SPECIAL","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L48_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"이번 일이 여러분의 인식을 쇄신시킬 기회임을 명심하시죠.","JPN":"今回の件が、皆さんに対する認識を改善できるチャンスであるということを忘れないでください。","ENG":"Treat this as your chance to correct perceptions.","TWN":"記住，這次的事是各位更新認知的機會。"},"stage":{"bg":"YOO_MI_NA_SPECIAL","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L50_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"소령은 농담을 싫어하나 보네.","JPN":"少佐は冗談が嫌いなようだ。","ENG":"Major, I see you don't like jokes.","TWN":"看來少校不喜歡開玩笑。"},"stage":{"bg":"YOO_MI_NA_SPECIAL","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"그쪽 마음에 들 수 있도록 진지하게 임해야겠는걸?","JPN":"そちらに気に入ってもらえるよう、真剣に挑まねばならないな。","ENG":"I'll be serious enough to suit you, then.","TWN":"為了讓你滿意，我應該要認真看待。"},"stage":{"bg":"YOO_MI_NA_SPECIAL","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"예. 건투를 빌겠습니다.","JPN":"はい、健闘を祈ります。","ENG":"Copy. I wish you good luck.","TWN":"是，祝妳好運。"},"stage":{"bg":"YOO_MI_NA_SPECIAL","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SCIENTIST_SWANSONG_NPC_NULL","text":{"KOREA":"각하. 밴시 부대가 준비되었습니다.","JPN":"閣下、バンシー部隊の準備が完了しました。","ENG":"Ma'am, Banshee unit is ready.","TWN":"閣下，女妖部隊已經準備好了。"},"stage":{"bg":"YOO_MI_NA_SPECIAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SCIENTIST_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL"},{"id":"L5_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"응. 보고해줘.","JPN":"ああ、報告してくれ。","ENG":"Good. Report.","TWN":"嗯，報告吧。"},"stage":{"bg":"YOO_MI_NA_SPECIAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SCIENTIST_SWANSONG_NPC_NULL","text":{"KOREA":"현재 스프리건 인자를 부여한 지휘관급 개체를 중심으로 부대를 편성했습니다.","JPN":"スプリガン因子を付与した指揮官級の個体を中心に部隊を編成しました。","ENG":"The unit is organized around Commander-class entities imbued with the Spriggan Factor.","TWN":"目前以賦予斯普利根因子的指揮官級個體為中心編成了部隊。"},"stage":{"bg":"YOO_MI_NA_SPECIAL","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SCIENTIST_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"SCIENTIST_SWANSONG_NPC_NULL","text":{"KOREA":"일반 개체는 메모리코어를 접목시켜 인위적으로 가능성을 배제시켰으니…….","JPN":"一般個体はメモリーコアを通して人工的に可能性を排除していますので……","ENG":"We grafted memory cores onto the regular units to artificially strip their possibilities...","TWN":"一般個體結合記憶核心，已經以人為方式排除可能性……"},"stage":{"bg":"YOO_MI_NA_SPECIAL","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SCIENTIST_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"SCIENTIST_SWANSONG_NPC_NULL","text":{"KOREA":"뿌리가 그들을 흡수하더라도, 통상적인 상황보다 시간을 벌 수 있을 겁니다.","JPN":"彼らが根に吸収されても、通常の状況よりは時間を稼げるかと。","ENG":"So even if the roots absorb them, it should buy more time than usual.","TWN":"就算根部吸收他們，應該也能比通常情況爭取更多時間。"},"stage":{"bg":"YOO_MI_NA_SPECIAL","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SCIENTIST_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"지휘관급 밴시는 후방에 배치시켜.","JPN":"指揮官級バンシーは後方に配置しろ。","ENG":"Keep the Commander-class Banshees in the rear.","TWN":"把指揮官級女妖安排在後方。"},"stage":{"bg":"YOO_MI_NA_SPECIAL","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SCIENTIST_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"뿌리는 스프리건 인자에 이끌리니, 거리를 확보하지 않으면 순식간에 당할 거야.","JPN":"根はスプリガン因子に引き寄せられる。距離を確保しないとあっという間にやられる。","ENG":"The roots are drawn to Spriggan Factors. If they get too close, they'll be taken in an instant.","TWN":"根部會被斯普利根因子吸引，要是不確保距離，就會瞬間被擊倒。"},"stage":{"bg":"YOO_MI_NA_SPECIAL","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SCIENTIST_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"SCIENTIST_SWANSONG_NPC_NULL","text":{"KOREA":"병사들의 배치는 어떻게 하시겠습니까?","JPN":"兵士の配置はどういたしましょうか？","ENG":"How shall we deploy the troops?","TWN":"妳打算怎麼配置士兵？"},"stage":{"bg":"YOO_MI_NA_SPECIAL","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SCIENTIST_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"전원 대기. 혹시 모를 상황을 대비해 무장 상태는 유지해.","JPN":"全員待機。万が一のために武装状態は維持するように。","ENG":"Have everyone stand by. Fully armed, just in case.","TWN":"全員待命，維持武裝狀態以防萬一。"},"stage":{"bg":"YOO_MI_NA_SPECIAL","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SCIENTIST_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"SCIENTIST_SWANSONG_NPC_NULL","text":{"KOREA":"외람되오나, 각하. 여건이 남는다면 합중국에 힘을 보태는 것은 어떨는지요.","JPN":"恐れ入りますが、閣下。余裕があるなら合衆国に力を貸してはいかがでしょうか。","ENG":"Forgive me, but if circumstances allow, perhaps we should aid the States?","TWN":"雖然很冒昧，但閣下，要是條件允許的話，助合眾國一臂之力怎麼樣？"},"stage":{"bg":"YOO_MI_NA_SPECIAL","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SCIENTIST_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"SCIENTIST_SWANSONG_NPC_NULL","text":{"KOREA":"그들에게 빚을 지워 둔다면 추후 활동에 큰 보탬이 될 것입니다.","JPN":"彼らに借りを作っておけば、今後の活動に大きく役立ちます。","ENG":"Putting them in our debt would greatly benefit future operations.","TWN":"要是讓他們對我們有所虧欠，應該會對之後的活動有很大的幫助。"},"stage":{"bg":"YOO_MI_NA_SPECIAL","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SCIENTIST_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"그럴 필요 없어.","JPN":"その必要はない。","ENG":"No need.","TWN":"不需要這樣。"},"stage":{"bg":"YOO_MI_NA_SPECIAL","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"합중국의 눈길이 챔버에 국한되려면, 그들의 패는 소모되는 편이 낫거든.","JPN":"合衆国の目をチェンバーに集中させるためには、彼らの駒を消耗させたほうがいいからな。","ENG":"If we want their attention fixed on Chamber, it's better if their pieces get spent.","TWN":"如果合眾國目光要侷限在密室，他們的牌還是消耗掉比較好。"},"stage":{"bg":"YOO_MI_NA_SPECIAL","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SCIENTIST_SWANSONG_NPC_NULL","text":{"KOREA":"예?","JPN":"はい？","ENG":"Pardon?","TWN":"什麼？"},"stage":{"bg":"YOO_MI_NA_SPECIAL","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SCIENTIST_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"저쪽을 신경 쓸 필요 없다는 소리야.","JPN":"向こうを気にする必要はないということだ。","ENG":"I'm saying don't worry about them.","TWN":"意思是不需要在意他們。"},"stage":{"bg":"YOO_MI_NA_SPECIAL","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SCIENTIST_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"부탁해?","JPN":"頼んだぞ？","ENG":"Understood?","TWN":"交給你囉？"},"stage":{"bg":"YOO_MI_NA_SPECIAL","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L26_1","type":"dialog","speaker":"SCIENTIST_SWANSONG_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"YOO_MI_NA_SPECIAL","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SCIENTIST_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SCIENTIST_SWANSONG_NPC_NULL","text":{"KOREA":"예. 알겠습니다.","JPN":"はい、かしこまりました。","ENG":"Understood.","TWN":"是，我知道了。"},"stage":{"bg":"YOO_MI_NA_SPECIAL","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SCIENTIST_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":null,"text":{"KOREA":"메스헤르츠 채널에서 전해드리는 속보입니다.","JPN":"マスヘルツチャンネルからの速報です。","ENG":"Breaking news, here from the Masshertz channel.","TWN":"這是梅斯赫爾茲頻道傳來的快報。"},"stage":{"bg":"BLACK","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":null,"text":{"KOREA":"이전 갑작스러운 침식 사태에 이어, 관리국이 다시 최고 등급 재난 경보를 발령했습니다.","JPN":"以前突如発生した侵食事態に続き、管理局が再び最高ランクの災害警報を発令しました。","ENG":"Following the recent sudden Corruption disaster, the Administration has once again issued its highest-level disaster alert.","TWN":"繼先前突如其來的侵蝕事件後，管理局再次發布了最高等級災難警報。"},"stage":{"bg":"BLACK","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":null,"text":{"KOREA":"관리 실패 이후 처음 발생한 대균열 확장 현상으로 인해 시민들의 불안감은 극에 달한 상황인데요.","JPN":"管理失敗以来初の大亀裂拡張現象により、市民の不安は高まる一方です。","ENG":"With the first Grand Dimension Crevice expansion since the Administration Failure, public anxiety is peaking.","TWN":"由於管理失敗後第一次發生的大峽谷擴張現象，居民們的不安達到了極點。"},"stage":{"bg":"BLACK","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":null,"text":{"KOREA":"관리국은 신속한 대응을 예고했지만, 구체적인 방안을 제시하지 못해 시니어가 부재한 도시는 혼란에…….","JPN":"管理局は迅速に対応するとのことですが、具体的な指針がないため、シニアが不在中の都市は混乱に……","ENG":"The Administration promised a swift response, but with no concrete plan, cities without Seniors are in turmoil...","TWN":"雖然管理局預告會迅速進行應對，但未能提出具體方案，Senior空缺的城市陷入混亂……"},"stage":{"bg":"BLACK","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"북방합의체와의 거래 당시, 당신은 전조 상황에서의 협력을 요구했었지.","JPN":"北方合意体との取引当時、君は前兆状況での協力を要求した。","ENG":"During our deal, you asked for cooperation in the OMEN situation.","TWN":"和北方和議會交易當時，你提出過在前兆情況下合作的請求吧。"},"stage":{"bg":"YOO_MI_NA_SPECIAL","bgm":"THEMA_SA_COMMANDER_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"약속대로 <color=#ffd34c>챔버</color>를 지키는 데에는 협력할게, 시니어 잭슨.","JPN":"約束通り、<color=#ffd34c>チェンバー</color>を守ることには協力する。シニア・ジャクソン。","ENG":"As promised, I'll help protect <color=#ffd34c>Chamber</color>, Senior Jackson.","TWN":"我會按照約定協助保護<color=#ffd34c>密室</color>，Senior傑森。"},"stage":{"bg":"YOO_MI_NA_SPECIAL","bgm":"THEMA_SA_COMMANDER_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"물론, 지금부터의 일은…….","JPN":"もちろん、これからのことは……","ENG":"Of course, from here on...","TWN":"當然，從現在開始的事……"},"stage":{"bg":"YOO_MI_NA_SPECIAL","bgm":"THEMA_SA_COMMANDER_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L43_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"내 나름의 방식으로 해결하겠지만.","JPN":"私のやり方で解決していくつもりだが。","ENG":"I'll handle things my own way.","TWN":"我會用自己的方式解決。"},"stage":{"bg":"YOO_MI_NA_SPECIAL","bgm":"THEMA_SA_COMMANDER_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};